+// ── Enums ─────────────────────────────────────────────────────────────
+
+/// Target audience for a playbook.
+#[derive(Clone, Copy, Debug, Eq, PartialEq, Hash, Serialize, Deserialize)]
+#[serde(rename_all = "snake_case")]
+pub enum Audience {
+    Operator,
+    Agent,
+    Developer,
+}
+
+impl Audience {
+    /// Human-readable label.
+    pub const fn label(self) -> &'static str {
+        match self {
+            Self::Operator => "Operator",
+            Self::Agent => "Agent",
+            Self::Developer => "Developer",
+        }
+    }
+
+    /// All variants.
+    pub const fn all() -> &'static [Self] {
+        &[Self::Operator, Self::Agent, Self::Developer]
+    }
+}
+
+impl std::fmt::Display for Audience {
+    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
+        f.write_str(self.label())
+    }
+}
+
+/// Playbook category.
+#[derive(Clone, Copy, Debug, Eq, PartialEq, Hash, Serialize, Deserialize)]
+#[serde(rename_all = "snake_case")]
+pub enum PlaybookCategory {
+    GettingStarted,
+    DailyOperations,
+    Troubleshooting,
+    Migration,
+    Security,
+    Performance,
+    Integration,
+    Advanced,
+}
+
+impl PlaybookCategory {
+    /// Human-readable label.
+    pub const fn label(self) -> &'static str {
+        match self {
+            Self::GettingStarted => "Getting Started",
+            Self::DailyOperations => "Daily Operations",
+            Self::Troubleshooting => "Troubleshooting",
+            Self::Migration => "Migration",
+            Self::Security => "Security",
+            Self::Performance => "Performance",
+            Self::Integration => "Integration",
+            Self::Advanced => "Advanced",
+        }
+    }
+
+    /// All variants in display order.
+    pub const fn all() -> &'static [Self] {
+        &[
+            Self::GettingStarted,
+            Self::DailyOperations,
+            Self::Troubleshooting,
+            Self::Migration,
+            Self::Security,
+            Self::Performance,
+            Self::Integration,
+            Self::Advanced,
+        ]
+    }
+}
+
+impl std::fmt::Display for PlaybookCategory {
+    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
+        f.write_str(self.label())
